import React, { useEffect } from 'react'
import { RxCross1 } from "react-icons/rx";
export const TOAST_TYPE = {
    SUCCESS: 'success',
    ERROR: 'error',
    WARNING: 'warning'
}

function Toast({ content, timerDelay = 1000, type, onClose }) {
    function getBackground(type) {
        let color = 'grey'
        switch (type) {
            case TOAST_TYPE.SUCCESS: color = '#B5F5AE'
                break
            case TOAST_TYPE.ERROR: color = '#F78B8B'
                break
            case TOAST_TYPE.WARNING: color = '#FABB4D'
                break
        }
        return color
    }
    function handleClose() {
        onClose()
    }
    // useEffect(() => {
    //     setTimeout(() => {
    //         onClose()
    //     }, [timerDelay])
    // })
    return (
        <>
            <div>{content}</div>
            <button className='close-btn' onClick={handleClose}><RxCross1 /></button>
        </>
    )
}

export default Toast
